{
  "terms": [
    {
      "term": "TT System",
      "simpleDefinition": "An earthing arrangement where the consumer provides their own connection to Earth, typically via a rod in the ground.",
      "anchor": "Consumer-provided earth electrode.",
      "misconception": "Thinking the electricity supplier provides the earth connection in a TT system."
    },
    {
      "term": "TN-S System",
      "simpleDefinition": "An earthing arrangement where the neutral and earth conductors are kept separate throughout the entire distribution system.",
      "anchor": "Separate neutral and earth all the way from the source.",
      "misconception": "Confusing TN-S with TN-C-S where the conductors are combined for part of the journey."
    },
    {
      "term": "TN-C-S System",
      "simpleDefinition": "An earthing arrangement where the neutral and earth are combined in the supply cable but separated at the property's intake.",
      "anchor": "Combined then Separated (often called PME).",
      "misconception": "Believing the earth and neutral remain combined inside the consumer's final circuits."
    },
    {
      "term": "ADS (Automatic Disconnection of Supply)",
      "simpleDefinition": "A safety system that automatically cuts off power during a fault to prevent electric shock.",
      "anchor": "The system that trips the breaker to keep people safe.",
      "misconception": "Thinking ADS is a single component rather than a combination of conductors and protective devices."
    },
    {
      "term": "CPC (Circuit Protective Conductor)",
      "simpleDefinition": "The specific conductor that connects the metal parts of equipment in a circuit to the main earthing terminal.",
      "anchor": "The earth wire inside a circuit cable.",
      "misconception": "Using the term CPC to describe the main earthing conductor that connects to the supplier."
    },
    {
      "term": "Main Protective Bonding",
      "simpleDefinition": "Conductors used to connect metallic services like water or gas pipes to the main earthing terminal.",
      "anchor": "Connecting incoming metal pipes to the earth terminal.",
      "misconception": "Believing bonding is the same as earthing; bonding is for equalizing potential, not for circuit protection."
    },
    {
      "term": "Earthing Conductor",
      "simpleDefinition": "The main conductor that connects the installation's main earthing terminal to the actual means of earthing (like a rod or supplier terminal).",
      "anchor": "The main link between the house and the earth source.",
      "misconception": "Confusing this with the CPCs that run to individual light switches or sockets."
    },
    {
      "term": "Earth Electrode",
      "simpleDefinition": "A metal rod, plate, or mesh buried in the ground to provide a physical connection to the earth.",
      "anchor": "The physical rod in the soil.",
      "misconception": "Thinking every earthing system requires a consumer-installed earth rod."
    },
    {
      "term": "Protective Device",
      "simpleDefinition": "A component such as a circuit breaker (MCB) or RCD designed to break the circuit during a fault.",
      "anchor": "The switch that trips or the fuse that blows.",
      "misconception": "Thinking a protective device only protects against overloads, when it is also vital for shock protection."
    }
  ],
  "anchorPhrases": [
    "TT uses an electrode",
    "TN-S is Separate",
    "TN-C-S is Combined then Separated",
    "CPC is for the circuit",
    "Bonding is for the pipes",
    "ADS requires both a path and a device"
  ],
  "misconceptionTargets": [
    "Interchanging CPC and Earthing Conductor",
    "Treating Bonding and Earthing as identical",
    "Assuming the supplier always provides the earth connection",
    "Thinking ADS is just a circuit breaker"
  ]
}

{
  "teachChecks": [
    {
      "title": "Earthing System Types",
      "objective": "Identify and distinguish between TT, TN-S, and TN-C-S earthing systems.",
      "retrievalTextLines": [
        "In the UK, we use three main earthing system arrangements to ensure safety, identified by letter codes. The TN-S system (Terre-Neutral-Separate) keeps the neutral and earth conductors completely separate from the transformer all the way to the consumer's installation. The supplier provides a dedicated earth terminal, often using the cable's lead sheath as the return path.",
        "The TN-C-S system (Terre-Neutral-Combined-Separate) combines the neutral and earth into a single conductor for the journey from the substation, but they are separated at the property's intake. This is the most common modern system, often called PME (Protective Multiple Earthing).",
        "The TT system (Terre-Terre) is used when the supplier does not provide an earth connection. In this case, the consumer must provide their own connection to the ground using an earth electrode, which is usually a metal rod driven into the soil."
      ],
      "hint": "Focus on whether the earth and neutral are separate, combined, or if the consumer has to provide their own rod."
    },
    {
      "title": "ADS Component Parts",
      "objective": "Identify the specific components that make up an ADS system.",
      "retrievalTextLines": [
        "Automatic Disconnection of Supply (ADS) is a safety strategy that uses several components working together to cut power during a fault. The Circuit Protective Conductor (CPC) is the earth wire within an individual circuit, such as the green and yellow wire in a twin and earth cable. This connects to the earthing conductor, which is the main cable linking the installation's main earthing terminal to the supplier's earth or an earth electrode.",
        "To prevent dangerous voltages between metal parts, we use main protective bonding to connect incoming metal services, like gas or water pipes, to the earth terminal. In specific areas like bathrooms, supplementary bonding may be used to link local metalwork together.",
        "Finally, protective devices, such as circuit breakers (MCBs) or RCDs, are the components that actually detect the fault current and trip to disconnect the power, completing the ADS process."
      ],
      "hint": "Remember that the CPC is for the circuit, while the earthing conductor is the main link to the source."
    }
  ]
}

